(()=>{"use strict";document.addEventListener("DOMContentLoaded",()=>{const t=document.querySelector("#stagify-test-connection"),e=document.querySelector("#stagify-test-result");t&&e&&t.addEventListener("click",async()=>{const s=t.textContent??"";t.disabled=!0,t.textContent="Testing…",t.classList.add("stagify-btn-loading"),e.textContent="",e.className="stagify-test-result";try{const t=new URLSearchParams({action:"stagify_test_connection",_ajax_nonce:stagifySettings.nonce}),s=await fetch(stagifySettings.ajaxUrl,{method:"POST",credentials:"same-origin",body:t}),n=await s.json();e.textContent=n.message,e.className="stagify-test-result "+(n.success?"stagify-test-result--success":"stagify-test-result--error")}catch{e.textContent="Request failed. Check your network.",e.className="stagify-test-result stagify-test-result--error"}finally{t.disabled=!1,t.textContent=s,t.classList.remove("stagify-btn-loading")}})})})();